def match_parens(lst):
    s1, s2 = lst
    def is_balanced(s):
        balance = 0
        for char in s:
            balance += 1 if char == '(' else -1
            if balance < 0:
                return False
        return balance == 0
    return 'Yes' if is_balanced(s1 + s2) or is_balanced(s2 + s1) else 'No'

